	function dd($var){
		var str = 'Type : '+(typeof $var)+'\n';
		if(typeof($var) === 'object'){
			for (prop in $var){ str+= prop +  " => " +$var[prop] + "\n"; }
		}
		else {
			str =  'Valeur : '+$var;
		}
		alert(str);
	}

	function ddc($var){
		console.log('Type : '+typeof($var));
		if(typeof($var) === 'object'){
			for (prop in $var){ console.log(prop +  " => " +$var[prop]); }
		}
		else {
			console.log('Valeur : '+$var);
		}
	}

